const insertWorkspaceExecOutputStreamChunk = `-- name: InsertWorkspaceExecOutputStreamChunk :one
WITH inserted AS (
    INSERT INTO workspace_process_stream_chunks (
        org_id,
        worker_group_id,
        project_id,
        environment_id,
        workspace_id,
        process_id,
        stream_name,
        direction,
        offset_start,
        offset_end,
        data,
        observed_at
    ) VALUES (
        $1,
        $2,
        $3,
        $4,
        $5,
        $6,
        $7::text,
        CASE WHEN $7::text = 'stdin' THEN 'input' ELSE 'output' END,
        $8,
        $9,
        $10,
        coalesce($11, now())
    )
    ON CONFLICT DO NOTHING
    RETURNING id, org_id, worker_group_id, project_id, environment_id, workspace_id, process_id, stream_name, direction, offset_start, offset_end, data, observed_at, expires_at, created_at
),
terminal_telemetry_outbox AS (
    INSERT INTO telemetry_outbox (
        org_id,
        worker_group_id,
        stream_kind,
        source_kind,
        source_id,
        stream_name,
        offset_start,
        idempotency_key,
        project_id,
        environment_id,
        workspace_id,
        resource_kind,
        resource_id,
        content,
        size_bytes,
        offset_end,
        source,
        kind,
        message,
        redaction_class,
        retention_class,
        observed_at
    )
    SELECT inserted.org_id,
           inserted.worker_group_id,
           'terminal_output',
           'workspace_process',
           inserted.process_id,
           inserted.stream_name::text,
           inserted.offset_start,
           'terminal_output:workspace_process:' || inserted.process_id::text || ':' || inserted.stream_name::text || ':' || inserted.offset_start::text || ':' || inserted.offset_end::text,
           inserted.project_id,
           inserted.environment_id,
           inserted.workspace_id,
           'workspace_process',
           inserted.process_id,
           inserted.data,
           octet_length(inserted.data)::bigint,
           inserted.offset_end,
           'worker',
           'terminal.output',
           'terminal.output',
           'standard',
           'standard',
           inserted.observed_at
      FROM inserted
    ON CONFLICT (org_id, stream_kind, source_kind, source_id, stream_name, idempotency_key) DO NOTHING
    RETURNING id
)
SELECT id, org_id, worker_group_id, project_id, environment_id, workspace_id, process_id, stream_name, direction, offset_start, offset_end, data, observed_at, expires_at, created_at
  FROM inserted
 WHERE (SELECT count(*) FROM terminal_telemetry_outbox) >= 0
`

